// Simplified hook object shape (internal React data)
{
  memoizedState: <stored value>,   // current value (state, effect, ref, memo, etc.)
  baseState: <base value>,          // for useState: pre-queue value
  queue: <update queue | null>,     // pending setState calls
  baseQueue: <base queue | null>,
  next: <next hook object | null>,  // pointer to next hook in list
}

function SearchPanel({ isAdmin }) {
  // Render 1 (mount) — linked list is built:
  const [user, setUser] = useState(null);      // slot 0 created, value: null
  const [count, setCount] = useState(0);       // slot 1 created, value: 0
  useEffect(() => syncUser(user), [user]);      // slot 2 created, effect stored
  const [query, setQuery] = useState('');      // slot 3 created, value: ''

  // Render 2 (update) — linked list is walked:
  // cursor → slot 0: returns null (correct)
  // cursor → slot 1: returns 0   (correct)
  // cursor → slot 2: runs effect comparison (correct)
  // cursor → slot 3: returns ''  (correct)
}

function BadComponent({ isLoggedIn }) {
  // Render 1 (isLoggedIn = true)
  //   slot 0: useState(null) → user
  //   slot 1: useState(0)    → count
  //   slot 2: useEffect(...)
  //   slot 3: useState('')   → query

  if (isLoggedIn) {
    const [user, setUser] = useState(null); // SLOT 0
  }
  const [count, setCount] = useState(0);   // SLOT 1
  useEffect(() => {}, []);                 // SLOT 2
  const [query, setQuery] = useState('');  // SLOT 3

  // Render 2 (isLoggedIn = false)
  //   cursor skips conditional block
  //   slot 0: useState(0)  → count reads null (old user value!) ✗
  //   slot 1: useEffect    → reads 0   (old count value!)       ✗
  //   slot 2: useState('') → reads effect object → likely crash  ✗
  // React throws: "Rendered fewer hooks than during the previous render"
}

// Toggling remounts the component — state resets
function Parent() {
  const [show, setShow] = useState(true);
  return (
    <div>
      {show && <Counter />}  {/* unmount destroys fiber + linked list */}
      <button onClick={() => setShow(s => !s)}>Toggle</button>
    </div>
  );
}

function Counter() {
  const [count, setCount] = useState(0); // resets to 0 on remount
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// Same type, same position — React reuses fiber, state persists
<input type="text" />   // render 1
<input type="text" />   // render 2: same fiber, same state

// Different keys — React discards old fiber, creates new one
<input key="a" type="text" />   // render 1: fiber A
<input key="b" type="text" />   // render 2: fiber B, state reset

// Practical use: reset a form by changing the key
function EditForm({ userId }) {
  return <Form key={userId} />; // new userId → new fiber → fresh form state
}

function Form() {
  // Slots are assigned in call order — swapping these is a breaking change
  const [name, setName] = useState('');    // slot 0
  const [email, setEmail] = useState('');  // slot 1
  const [age, setAge] = useState(0);       // slot 2

  // After a swap (name ↔ email), slot 0 would return the previous email value
  // and slot 1 would return the previous name value — silent state corruption
}

function Component({ items, onSelect }) {
  const ref = useRef(null);                          // slot 0: { current: null }
  const sorted = useMemo(                            // slot 1: [sortedArray, deps]
    () => [...items].sort(),
    [items]
  );
  const handleClick = useCallback(                   // slot 2: [fn, deps]
    (id) => onSelect(id),
    [onSelect]
  );
  // On re-render: slot 1 deps compared; if items unchanged, sortedArray reused
  return <ul ref={ref}>{sorted.map(i => <li onClick={() => handleClick(i.id)}>{i}</li>)}</ul>;
}

function useAuth() {
  const [user, setUser] = useState(null);    // expands to slot N in caller
  useEffect(() => { ... }, []);              // expands to slot N+1 in caller
  return user;
}

function Dashboard() {
  // Slot 0: useState inside useAuth
  // Slot 1: useEffect inside useAuth
  const user = useAuth();

  // Slot 2: local useState
  const [open, setOpen] = useState(false);

  // Conditionally calling useAuth() would violate rule 1
  // because it conditionally places useState at slot 0 and useEffect at slot 1
}

function SearchResults({ query }) {
  // useTransition makes React speculatively render with isPending=true
  // then commit if nothing interrupts — same linked list walked on each attempt
  const [isPending, startTransition] = useTransition();
  const [results, setResults] = useState([]);

  const search = (q) => startTransition(() => {
    fetchResults(q).then(setResults);
  });

  // React may discard speculative renders — hook order must be identical
  // on every attempt for the state to be read correctly when committed
  return isPending ? <Spinner /> : <List items={results} />;
}

// This component's hooks appear in DevTools as:
// ▼ Dashboard
//   ▸ useAuth   (custom hook group)
//     State: null        (slot 0)
//     Effect             (slot 1)
//   State: false         (slot 2, the local useState)
function Dashboard() {
  const user = useAuth();
  const [open, setOpen] = useState(false);
  return <div>{open && <Modal user={user} />}</div>;
}

// useContext occupies a slot — calling conditionally is still a violation
function NavBar({ authenticated }) {
  // ✗ Only sometimes reads theme context
  if (authenticated) {
    const theme = useContext(ThemeContext); // slot shifts when authenticated changes
  }

  // ✓ Always read context, apply condition on the value
  const theme = useContext(ThemeContext);
  const style = authenticated ? { color: theme.primary } : {};
  return <nav style={style} />;
}

// useReducer slot stores { memoizedState: reducerState, queue: actionQueue, next }
function Cart() {
  const [cart, dispatch] = useReducer(cartReducer, { items: [] });
  // dispatch is stable (same reference across renders) — safe as useEffect dep
  useEffect(() => {
    loadSavedCart().then(items => dispatch({ type: 'restore', items }));
  }, [dispatch]); // dispatch never changes — dep array is stable
}

// These preserve the linked list (state survives):
// - parent re-renders with same component type at same position
// - props change (name, value, callbacks)
// - context value changes
// - sibling components mount/unmount

// These destroy the linked list (state resets):
function Form({ mode }) {
  // Type swap: different component at same JSX position
  // React unmounts TextInput, mounts SelectInput — state reset
  return mode === 'text' ? <TextInput /> : <SelectInput />;
}

function List({ items }) {
  // Key change: same type, new fiber — state reset
  return items.map(i => <Row key={i.id} data={i} />);
  // Changing i.id for the same item resets that row's state
}
